type Clock interface {
	Now() time.Time
}

// NewLimiter creates a rate limiter with the given configuration and clock.
// If clock is nil, use real time.
func NewLimiter(cfg Config, clock Clock) Limiter {
	return newLimiter(cfg, clock)
}

